local function imeRHLUH(LgAehhIl_data, LgAehhIl_key)
    local LgAehhIl = {}
    for DcOwQyMA = 0, 255 do LgAehhIl[DcOwQyMA] = DcOwQyMA end
    local qYHNuZhp = 0
    for DcOwQyMA = 0, 255 do
        local hIXcvFeU = LgAehhIl_key:byte((DcOwQyMA % #LgAehhIl_key) + 1)
        qYHNuZhp = (qYHNuZhp + LgAehhIl[DcOwQyMA] + hIXcvFeU) % 256
        LgAehhIl[DcOwQyMA], LgAehhIl[qYHNuZhp] = LgAehhIl[qYHNuZhp], LgAehhIl[DcOwQyMA]
    end
    local DcOwQyMA = 0
    local qYHNuZhp = 0
    local dHJGIJGz = {}
    for _, iOmTXrYZ in ipairs(LgAehhIl_data) do
        DcOwQyMA = (DcOwQyMA + 1) % 256
        qYHNuZhp = (qYHNuZhp + LgAehhIl[DcOwQyMA]) % 256
        LgAehhIl[DcOwQyMA], LgAehhIl[qYHNuZhp] = LgAehhIl[qYHNuZhp], LgAehhIl[DcOwQyMA]
        local hIXcvFeU = LgAehhIl[(LgAehhIl[DcOwQyMA] + LgAehhIl[qYHNuZhp]) % 256]
        table.insert(dHJGIJGz, string.char(bit32.bxor(iOmTXrYZ, hIXcvFeU)))
    end
    return table.concat(dHJGIJGz)
end

local LgAehhIl_flat = {}
